                  ? "s"
                  : ""}
              </p>
            </div>
            <div className="flex gap-2 w-full sm:w-auto">
              <Button
                onClick={() => setShowManualRegistration(true)}
                size="sm"
                className="w-full sm:w-auto"
              >
                <Plus className="h-4 w-4 mr-2" />
                Add Registration
              </Button>
              {registrations.length > 0 && (
                <Button
